import React, {useState} from 'react'
import styled from 'styled-components'


const Hr = styled.div `
width:0;
height:1px;
background-color:#1C1C1C;
transition:all 0.3s ease-in;
`

const Messages = styled.div `
${props => props.active && `color:#1C1C1C;& ${Hr} {width:100%;}`}
transition:all 0.5s ease-in-out;
&:hover {
	cursor:pointer;
	color:#1C1C1C;
}
&:hover ${Hr} {
	width:100%;
	color:#1C1C1C;
}
`

const MyItems = styled.div `
${props => props.active && `color:#1C1C1C;& ${Hr} {width:100%;}`}
transition:all 0.5s ease-in-out;
margin-top:20px;
&:hover {
	cursor:pointer;
	color:#1C1C1C;
}
&:hover ${Hr} {
	width:100%;
}
`

const MyProfile = styled.div `
${props => props.active && `color:#1C1C1C;& ${Hr} {width:100%;}`}
transition:all 0.5s ease-in-out;
margin-top:20px;
&:hover {
	cursor:pointer;
	color:#1C1C1C;
}
&:hover ${Hr} {
	width:100%;
}
`

const Settings = styled.div `
${props => props.active && `color:#1C1C1C;& ${Hr} {width:100%;}`}
transition:all 0.5s ease-in-out;
margin-top:20px;
&:hover {
	cursor:pointer;
	color:#1C1C1C;
}
&:hover ${Hr} {
	width:100%;
}
`

const LeftBodyPart = styled.div `
font-size:0.9rem;
width:20%;
display:flex;
justify-content:center;
align-items:flex-start;
flex-direction:column;
color:grey;
`


export default function MeSidebar (props) {
	const initialState = {
		messageActive:true,
		myItemsActive:false,
		myProfileActive:false,
		settingsActive:false
	}

	props.sidebarSelect = initialState

	const [active, setActive] = useState(initialState)

	const onMessageClick = () => {
		setActive({...initialState, messageActive:true})
	}

	const onMyItemsClick = () => {
		setActive({...initialState, myItemsActive:true, messageActive:false})
	}

	const onMyProfileClick = () => {
		setActive({...initialState, myProfileActive:true, messageActive:false})
	}

	const onSettingsClick = () => {
		setActive({...initialState, settingsActive:true, messageActive:false})
	}

	return (
		<LeftBodyPart>
			<Messages active={active.messageActive} onClick={onMessageClick}>Messages<Hr /></Messages>
			<MyItems active={active.myItemsActive} onClick={onMyItemsClick}>My Items<Hr /></MyItems>
			<MyProfile active={active.myProfileActive} onClick={onMyProfileClick}>My Profile<Hr /></MyProfile>
			<Settings active={active.settingsActive} onClick={onSettingsClick}>Settings<Hr /></Settings>
		</LeftBodyPart>
	)
}
